 1	import React, { ClipboardEvent, FC, MouseEventHandler, useState } from 'react';
 2	
 3	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 4	import { Button, clipboardCopyFunc, Tooltip } from '@patternfly/react-core';
 5	import { CopyIcon } from '@patternfly/react-icons';
 6	
 7	import './SimpleCopyButton.scss';
 8	
 9	type SimpleCopyButtonProps = {
10	  textToCopy: string;
11	};
12	
13	const SimpleCopyButton: FC<SimpleCopyButtonProps> = ({ textToCopy }) => {
14	  const { t } = useKubevirtTranslation();
15	  const [copiedState, setCopiedState] = useState<boolean>(false);
16	
17	  const handleClick = (event: ClipboardEvent<HTMLInputElement>) => {
18	    clipboardCopyFunc(event, textToCopy);
19	    setCopiedState(true);
20	  };
21	
22	  return (
23	    <Tooltip
24	      aria="none"
25	      aria-live="polite"
26	      content={copiedState ? <div>{t('Copied')}</div> : <div>{t('Copy to clipboard')}</div>}
27	      entryDelay={300}
28	      exitDelay={0}
29	      maxWidth="150px"
30	      onTooltipHidden={() => setCopiedState(false)}
31	      position="top"
32	      trigger="mouseenter focus click"
33	    >
34	      <Button
35	        aria-label="Copy text to clipboard"
36	        icon={<CopyIcon />}
37	        id="kubevirt-simple-copy-button__button"
38	        onClick={handleClick as unknown as MouseEventHandler<HTMLButtonElement>}
39	      />
40	    </Tooltip>
41	  );
42	};
43	
44	export default SimpleCopyButton;

